const items = $input.all();
const item = items[0].json;
const isTelegram = item.message !== undefined;

let platform, userId, chatId, text, name;

if (isTelegram) {
  platform = "telegram";
  userId = String(item.message.from.id);
  chatId = item.message.chat.id;
  text = item.message.text || "";
  name = item.message.from.first_name + " " + (item.message.from.last_name || "");
} else {
  platform = "whatsapp";
  userId = item.From;
  chatId = item.From;
  text = item.Body || "";
  name = item.ProfileName || "Cliente";
}

const sessionId = platform + "_" + userId;
return [{
  json: { platform, userId, chatId, text: text.trim(), name: name.trim(), sessionId }
}];

const response = $input.first().json;
const candidates = response.candidates || [];
const text = candidates[0]?.content?.parts?.[0]?.text || "¡Hola! Soy el asistente de Kyros Barber. ¿En que puedo ayudarte hoy?";

return [{
  json: {
    ...$input.first().json,
    aiResponse: text
  }
}];

const input = $input.first().json;
const message = input.aiResponse;

let output;
if (input.platform === "telegram") {
  output = {
    chat_id: input.chatId,
    text: message,
    parse_mode: "Markdown"
  };
} else {
  output = {
    To: input.chatId,
    Body: message
  };
}

return [{ json: { output, platform: input.platform } }];
